import { isEmpty } from 'lodash-es';
import { type PropsWithChildren } from 'react';

import { ColorScaleContext } from '../contexts/color-scale.context.js';
import { useMapConfig } from '../hooks/use-map-config.js';
import { buildScaleFromLegendConfig } from '../utils/build-scale-from-legend-config.js';

/**
 * This provider will hold the scale used to map from a value of the domain
 * to a color in the color palette (range) or undefined in case is out of the
 * domain. This is valid if the consumer set a layer to be colored by the
 * legend, else this provider will be undefined.
 * As we use different scales, the consumer (of this provider) will need to
 * set some type guards to ensure ts compliance.
 * Because of that and to ease the consumption of this provider, we created
 * another one that make use of this scale.
 * @see {@link LayerColorStrategyProvider}
 * @example to build a legend the raw scale could be needed
 * @param categories - Available categories to be shown in the legend
 * @param dataMax - Maximum value present in the data
 * @param children -
 */
export const ColorScaleProvider = ({
  categories,
  dataMax,
  children,
}: PropsWithChildren<{
  categories: string[];
  dataMax: number;
}>) => {
  const { legend } = useMapConfig();

  if (isEmpty(legend)) {
    return <>{children}</>;
  }

  const scale = buildScaleFromLegendConfig(legend, categories, dataMax);

  return (
    <ColorScaleContext.Provider value={scale}>
      {children}
    </ColorScaleContext.Provider>
  );
};
